package be.schaubroeck.lpb.rkm.rekenmotor.factory;

import be.schaubroeck.lpb.rkm.artikelmotor.ArtikelMotorDataManagerFactory;
import be.schaubroeck.lpb.rkm.artikelmotor.ArtikelMotorResultaatHandler;
import be.schaubroeck.lpb.rkm.artikelmotor.ArtikelMotorResultaatHandlerImp;
import be.schaubroeck.lpb.rkm.artikelmotor.ArtikelMotorService;
import be.schaubroeck.lpb.rkm.artikelmotor.CachingArtikelManager;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenMotorStrategy;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenMotorStrategyFactory;
import be.schaubroeck.lpb.rkm.rekenmotor.results.BerekenNettoFiscaalVorigJaarResultaatHandlerImpl;
import be.schaubroeck.lpb.rkm.rekenmotor.results.BijsturenEurocentResultaatHandlerImp;
import be.schaubroeck.lpb.rkm.rekenmotor.results.MaandtotaalResultaatHandlerImp;
import be.schaubroeck.lpb.rkm.rekenmotor.results.MetArtikelResultaatHandlerImp;
import be.schaubroeck.lpb.rkm.rekenmotor.results.NeutraliseerResultaatHandlerImp;
import be.schaubroeck.lpb.rkm.rekenmotor.results.ResultaatHandler;
import be.schaubroeck.lpb.rkm.rekenmotor.results.ResultaatHandlerImp;
import be.schaubroeck.lpb.rkm.rekenmotor.results.SociaalRekenenResultaatHandlerImp;
import be.schaubroeck.lpb.rkm.rekenmotor.results.VermijdenFiche25ResultaatHandlerImp;
import be.schaubroeck.lpb.rkm.rekenmotor.results.VormArtikelsHandlerImp;
import be.schaubroeck.lpb.rkm.rekenmotor.service.ControlesRekenResultatenService;
import be.schaubroeck.lpb.rkm.rekenmotor.service.NlpGlobalService;
import be.schaubroeck.lpb.rkm.rekenmotor.util.ArtikelLoonElementManagerFactory;
import be.schaubroeck.lpb.tools.Admin;
import be.schaubroeck.lpb.tools.service.AfwartAkeService;
import be.schaubroeck.lpb.tools.service.AfwartRegelService;
import be.schaubroeck.lpb.tools.service.AfwartUitzonderingService;
import be.schaubroeck.lpb.tools.service.ArtikelAgendaService;
import be.schaubroeck.lpb.tools.service.ArtikelFamilieService;
import be.schaubroeck.lpb.tools.service.ArtikelHoofdService;
import be.schaubroeck.lpb.tools.service.ArtikelService;
import be.schaubroeck.lpb.tools.service.ControleAgendaService;
import be.schaubroeck.lpb.tools.service.MaandTotaalService;
import be.schaubroeck.lpb.tools.service.ManueleTussenkomstService;
import be.schaubroeck.lpb.tools.service.RegulAgendaService;
import be.schaubroeck.lpb.tools.service.RekenResultatenService;
import be.schaubroeck.lpb.tools.service.SleutelTussenkomstService;
import be.schaubroeck.lpb.tools.service.WachtAgendaService;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.beans.factory.annotation.Qualifier;

public class RekenMotorStrategyFactoryImp implements RekenMotorStrategyFactory {

    @Autowired
    private ManueleTussenkomstService manueleTussenkomstService;

    @Autowired
    private RekenResultatenService rekenResultatenService;

    @Autowired
    @Qualifier("rekenmotorNlpGlobalService")
    private NlpGlobalService nlpGlobalService;

    @Autowired
    private WachtAgendaService wachtAgendaService;

    @Autowired
    private RegulAgendaService regulAgendaService;

    @Autowired
    private MaandTotaalService maandTotaalService;

    @Autowired
    private ArtikelMotorService artikelMotorService;

    @Autowired
    private ArtikelLoonElementManagerFactory artikelLoonElementManagerFactory;

    @Autowired
    @Qualifier("artikelDataManagerFactory")
    private ArtikelMotorDataManagerFactory artikelMotorDataManagerFactory;

    @Autowired
    private ArtikelHoofdService artikelHoofdService;

    @Autowired
    private ArtikelService artikelService;

    @Autowired
    private ArtikelFamilieService artikelFamilieService;

    @Autowired
    private AfwartRegelService afwartRegelService;

    @Autowired
    private AfwartUitzonderingService afwartUitzonderingService;

    @Autowired
    private AfwartAkeService afwartAkeService;

    @Autowired
    private SleutelTussenkomstService sleutelTussenkomstService;

    @Autowired
    private ArtikelAgendaService artikelAgendaService;

    @Autowired
    private ControleAgendaService controleAgendaService;

    @Autowired
    private ControlesRekenResultatenService controlesRekenResultatenService;

    private RekenMotorStrategy createCommonStrategy(Admin admin) {
        RekenMotorStrategy strategy = new RekenStrategyImp();
        strategy.setRegulManagerFactory(new RegulManagerFactoryImp());
        strategy.setPreBerekeningInterpreter(new PreBerekeningInterpreterImp(nlpGlobalService.getAardKodeExtensieFacade()));
        strategy.setArtikelManager(
                new CachingArtikelManager(admin, artikelService, artikelFamilieService, afwartRegelService, afwartUitzonderingService, afwartAkeService));
        return strategy;

    }

    @Override
    public RekenMotorStrategy getStandaardStrategy(Admin admin) {
        RekenMotorStrategy strategy = createCommonStrategy(admin);
        strategy.setRekenChainFactory(new RekenChainFactoryImp(admin, nlpGlobalService));
        strategy.setResultaatHandler(new ResultaatHandlerImp(rekenResultatenService, wachtAgendaService, regulAgendaService, controleAgendaService,
                controlesRekenResultatenService));
        return strategy;
    }

    @Override
    public RekenMotorStrategy getNeutralisatieStrategy(Admin admin) {
        return getNeutralisatieStrategy(admin, true);
    }

    @Override
    public RekenMotorStrategy getNeutralisatieStrategy(Admin admin, boolean persisteerRekenResultaten) {
        RekenMotorStrategy strategy = createCommonStrategy(admin);
        strategy.setRekenChainFactory(new NeutraliseerChainFactory(admin, nlpGlobalService));
        NeutraliseerResultaatHandlerImp handler =
                new NeutraliseerResultaatHandlerImp(rekenResultatenService, wachtAgendaService, controleAgendaService, controlesRekenResultatenService,
                        manueleTussenkomstService, regulAgendaService, sleutelTussenkomstService, maandTotaalService);
        handler.setPersisteerRekenResultaten(persisteerRekenResultaten);
        strategy.setResultaatHandler(handler);
        return strategy;
    }

    @Override
    public RekenMotorStrategy getSociaalRekenenStrategy(Admin admin) {
        RekenMotorStrategy strategy = createCommonStrategy(admin);
        strategy.setRekenChainFactory(new SociaalRekenenChainFactory(admin, nlpGlobalService));
        ArtikelMotorResultaatHandler artikelHandler = new ArtikelMotorResultaatHandlerImp(artikelHoofdService, artikelService, artikelAgendaService);
        strategy.setArtikelMotorResultaatHandler(artikelHandler);
        strategy.setResultaatHandler(
                new SociaalRekenenResultaatHandlerImp(rekenResultatenService, maandTotaalService, wachtAgendaService, regulAgendaService,
                        controleAgendaService, controlesRekenResultatenService, artikelMotorService, artikelHandler, artikelLoonElementManagerFactory,
                        artikelMotorDataManagerFactory, strategy.getArtikelManager(), manueleTussenkomstService, sleutelTussenkomstService, nlpGlobalService));
        return strategy;
    }

    @Override
    public RekenMotorStrategy getMaandTotalenStrategy(Admin admin) {
        RekenMotorStrategy strategy = createCommonStrategy(admin);
        strategy.setRekenChainFactory(new RekenChainFactoryImp(admin, nlpGlobalService));
        ArtikelMotorResultaatHandler artikelHandler = new ArtikelMotorResultaatHandlerImp(artikelHoofdService, artikelService, artikelAgendaService);
        strategy.setArtikelMotorResultaatHandler(artikelHandler);
        strategy.setResultaatHandler(
                new MaandtotaalResultaatHandlerImp(rekenResultatenService, maandTotaalService, wachtAgendaService, regulAgendaService,
                        artikelMotorService, artikelHandler, artikelLoonElementManagerFactory, artikelMotorDataManagerFactory, strategy.getArtikelManager(),
                        controleAgendaService, controlesRekenResultatenService, nlpGlobalService));
        return strategy;
    }

    @Override
    public RekenMotorStrategy getMetArtikelStrategy(Admin admin) {
        RekenMotorStrategy strategy = createCommonStrategy(admin);
        strategy.setRekenChainFactory(new RekenChainFactoryImp(admin, nlpGlobalService));
        ArtikelMotorResultaatHandler artikelHandler = new ArtikelMotorResultaatHandlerImp(artikelHoofdService, artikelService, artikelAgendaService);
        strategy.setArtikelMotorResultaatHandler(artikelHandler);
        strategy.setResultaatHandler(
                new MetArtikelResultaatHandlerImp(rekenResultatenService, wachtAgendaService, regulAgendaService, artikelMotorService, artikelHandler,
                        strategy.getArtikelManager(), artikelMotorDataManagerFactory, controleAgendaService, controlesRekenResultatenService));
        return strategy;
    }

    @Override
    public RekenMotorStrategy getBijsturenEuroCentStrategy(Admin admin) {
        RekenMotorStrategy strategy = createCommonStrategy(admin);
        strategy.setRekenChainFactory(new NeutraliseerChainFactory(admin, nlpGlobalService));
        ResultaatHandler handler =
                new BijsturenEurocentResultaatHandlerImp(rekenResultatenService, wachtAgendaService, regulAgendaService, controleAgendaService,
                        controlesRekenResultatenService, manueleTussenkomstService, maandTotaalService);
        strategy.setResultaatHandler(handler);
        return strategy;
    }

    @Override
    public RekenMotorStrategy getVormArtikelStrategy(Admin admin) {
        RekenMotorStrategy strategy = createCommonStrategy(admin);
        strategy.setRekenChainFactory(new RekenChainFactoryImp(admin, nlpGlobalService));
        ArtikelMotorResultaatHandler artikelHandler = new ArtikelMotorResultaatHandlerImp(artikelHoofdService, artikelService, artikelAgendaService);
        strategy.setArtikelMotorResultaatHandler(artikelHandler);
        strategy.setResultaatHandler(
                new VormArtikelsHandlerImp(maandTotaalService, wachtAgendaService, regulAgendaService, artikelMotorService, artikelHandler,
                        artikelLoonElementManagerFactory, artikelMotorDataManagerFactory, strategy.getArtikelManager(), controleAgendaService, nlpGlobalService));
        return strategy;
    }

    @Override
    public RekenMotorStrategy getVermijdenFiche25Strategy(Admin admin) {
        RekenMotorStrategy strategy = createCommonStrategy(admin);
        strategy.setRekenChainFactory(new RekenChainFactoryImp(admin, nlpGlobalService));
        ArtikelMotorResultaatHandler artikelHandler = new ArtikelMotorResultaatHandlerImp(artikelHoofdService, artikelService, artikelAgendaService);
        strategy.setArtikelMotorResultaatHandler(artikelHandler);
        strategy.setResultaatHandler(
                new VermijdenFiche25ResultaatHandlerImp(rekenResultatenService, maandTotaalService, wachtAgendaService, regulAgendaService,
                        artikelMotorService, artikelHandler, artikelLoonElementManagerFactory, artikelMotorDataManagerFactory, strategy.getArtikelManager(),
                        controleAgendaService, controlesRekenResultatenService, nlpGlobalService));
        return strategy;
    }


    @Override
    public RekenMotorStrategy getBerekenVorigFiscaalJaarStrategy(Admin admin) {
        RekenMotorStrategy strategy = createCommonStrategy(admin);
        strategy.setRekenChainFactory(new RekenChainFactoryImp(admin, nlpGlobalService));
        ArtikelMotorResultaatHandler artikelHandler = new ArtikelMotorResultaatHandlerImp(artikelHoofdService, artikelService, artikelAgendaService);
        strategy.setArtikelMotorResultaatHandler(artikelHandler);
        strategy.setResultaatHandler(
                new BerekenNettoFiscaalVorigJaarResultaatHandlerImpl(rekenResultatenService, maandTotaalService, wachtAgendaService, regulAgendaService,
                        artikelMotorService, artikelHandler, artikelLoonElementManagerFactory, artikelMotorDataManagerFactory, strategy.getArtikelManager(),
                        controleAgendaService, controlesRekenResultatenService, nlpGlobalService));
        return strategy;
    }
}
